const searches = [{"q": "AI Operations Manager", "l": "Delhi, India", "platform": "indeed_india"}, {"q": "AI Project Manager", "l": "Delhi, India", "platform": "indeed_india"}, {"q": "AI Customer Success", "l": "Delhi, India", "platform": "indeed_india"}, {"q": "AI Strategy Consultant", "l": "India", "platform": "indeed_india"}, {"q": "Customer Success Manager", "l": "Delhi, India", "platform": "indeed_india"}, {"q": "Project Manager", "l": "Delhi NCR", "platform": "indeed_india"}, {"q": "Operations Manager", "l": "Delhi NCR", "platform": "indeed_india"}, {"q": "AI Operations", "l": "Netherlands", "platform": "indeed_eu"}, {"q": "AI Customer Success", "l": "Europe", "platform": "indeed_eu"}, {"q": "Customer Success Manager", "l": "Netherlands", "platform": "indeed_eu"}];
return searches.map(s => ({
  json: {
    url: `https://in.indeed.com/jobs?q=${encodeURIComponent(s.q)}&l=${encodeURIComponent(s.l)}&fromage=1&sort=date&limit=20`,
    source_platform: s.platform
  }
}));

const html = typeof $input.first().json === 'string' ? $input.first().json : ($input.first().json.data || '');
const sourcePlatform = $('Build Search URLs').first().json.source_platform;

const jobs = [];

// Extract job IDs from Indeed HTML
const jkMatches = html.match(/data-jk="([a-zA-Z0-9]+)"/g) || [];
const titleMatches = html.match(/class="jobTitle[^"]*"[^>]*><[^>]+>([^<]+)<\/span>/g) || [];
const companyMatches = html.match(/data-testid="company-name"[^>]*>([^<]+)</g) || [];
const locationMatches = html.match(/data-testid="text-location"[^>]*>([^<]+)</g) || [];

const seenIds = new Set();
for (let i = 0; i < jkMatches.length; i++) {
  const idMatch = jkMatches[i].match(/"([a-zA-Z0-9]+)"/);
  if (!idMatch) continue;
  const jk = idMatch[1];
  if (seenIds.has(jk)) continue;
  seenIds.add(jk);

  const title = titleMatches[i] ? titleMatches[i].replace(/<[^>]+>/g, '').trim() : 'Unknown';
  const company = companyMatches[i] ? companyMatches[i].replace(/<[^>]+>/g, '').trim() : 'Unknown';
  const location = locationMatches[i] ? locationMatches[i].replace(/<[^>]+>/g, '').trim() : 'Unknown';

  jobs.push({
    job_id: jk,
    job_title: title,
    company: company,
    location: location,
    job_url: `https://in.indeed.com/viewjob?jk=${jk}`,
    source_platform: sourcePlatform
  });
}

return jobs.map(j => ({ json: j }));

const fs = require('fs');
const path = require('path');

const cacheDir = 'C:/Users/Dev/Desktop/Job Agents/job-agent/setup/cache';
if (!fs.existsSync(cacheDir)) fs.mkdirSync(cacheDir, { recursive: true });

// Per-platform cache file
const item = $input.first().json;
const platform = item.source_platform || 'unknown';
const cacheFile = path.join(cacheDir, `seen_${platform.replace(/[^a-z0-9_]/gi, '_')}.json`);

let seen = [];
try { seen = JSON.parse(fs.readFileSync(cacheFile, 'utf-8')); } catch (e) {}

const url = item.job_url || item.job_id || '';
if (!url) return [];
if (seen.includes(url)) return []; // Already seen

seen.push(url);
if (seen.length > 5000) seen = seen.slice(-3000);
fs.writeFileSync(cacheFile, JSON.stringify(seen));

return [{ json: item }];

const html = typeof $input.first().json === 'string' ? $input.first().json : ($input.first().json.data || '');
const prev = $('Deduplicate').first().json;

const descMatch = html.match(/id="jobDescriptionText"[^>]*>([\s\S]*?)<\/div>/);
let description = '';
if (descMatch) {
  description = descMatch[1].replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim();
}
if (!description || description.length < 50) {
  description = `${prev.job_title} at ${prev.company}, ${prev.location}. See: ${prev.job_url}`;
}

return [{ json: { ...prev, description: description.substring(0, 3000) } }];
